	@Order(Integer.MAX_VALUE - 3)
	void medicalRecordsQueryNineBenchmarkLifecycleRejectsConditionCodeAnchor() throws Exception {
		ThemeQueryBenchmark benchmark = newBenchmark(Theme.MEDICAL_RECORDS, 9);

		benchmark.setup();
		try {
			String initialPlan = benchmark.explainOptimizedPlan();
			assertTrue(initialPlan.contains("finite-anchor:condCode[valid"),
					"Expected q9 benchmark setup to expose the condition-code finite anchor candidate\n"
							+ initialPlan);
			assertFalse(initialPlan.contains("selected=finite-anchor:condCode"),
					"q9 benchmark setup should reject a condition-code finite anchor that only wins by a "
							+ "near-tie scalar work estimate while worsening final rows and intermediate surface\n"
							+ initialPlan);

			long expectedBenchmarkResult = expectedBenchmarkResult(Theme.MEDICAL_RECORDS, 9);
			for (int i = 0; i < 5; i++) {
				assertEquals(expectedBenchmarkResult, benchmark.executeQuery());
			}
			String plan = benchmark.explainOptimizedPlan();
			assertTrue(plan.contains("finite-anchor:condCode[valid"),
					"Expected q9 benchmark lifecycle to expose the condition-code finite anchor candidate\n" + plan);
			assertFalse(plan.contains("selected=finite-anchor:condCode"),
					"q9 benchmark lifecycle should reject a condition-code finite anchor that only wins by a "
							+ "near-tie scalar work estimate while worsening final rows and intermediate surface\n"
							+ plan);
		} finally {
			benchmark.tearDown();
		}
	}

	private static void deleteBenchmarkStore() throws Exception {
		Path store = Path.of("target", "lmdb-theme-query-benchmark");
		if (!Files.exists(store)) {
			return;
		}
		try (Stream<Path> paths = Files.walk(store)) {
			for (Path path : paths.sorted(Comparator.reverseOrder()).collect(Collectors.toList())) {
				Files.delete(path);
			}
		}
	}

	@Test
	void secondBenchmarkTrialReusesPersistedJoinEstimatorSnapshot() throws Exception {
		Path store = Path.of("target", "lmdb-theme-query-benchmark", "complete", "join-estimator.rjes");
		Path metadata = store.resolve("metadata.bin");

		ThemeQueryBenchmark first = newBenchmark(Theme.MEDICAL_RECORDS, 0);
		first.setup();
		try {
			assertBenchmarkQueryCount(first, Theme.MEDICAL_RECORDS, 0);
		} finally {
			first.tearDown();
		}

		assertTrue(Files.isDirectory(store),
				"Expected persisted join-estimator store directory after first benchmark trial");
		assertTrue(Files.exists(metadata), "Expected persisted join-estimator metadata after first benchmark trial");
		List<Path> sketchFiles = persistedSketchFiles(store);
		assertTrue(!sketchFiles.isEmpty(),
				"Expected persisted join-estimator sketch files after first benchmark trial");
		long metadataLastModified = Files.getLastModifiedTime(metadata).toMillis();
		List<Long> sketchLastModified = lastModifiedMillis(sketchFiles);

		ThemeQueryBenchmark second = newBenchmark(Theme.MEDICAL_RECORDS, 1);
		second.setup();
		try {
			assertBenchmarkQueryCount(second, Theme.MEDICAL_RECORDS, 1);
		} finally {
			second.tearDown();
		}

		assertEquals(metadataLastModified, Files.getLastModifiedTime(metadata).toMillis(),
				"Second benchmark trial should reuse the persisted join-estimator metadata instead of rewriting it");
		assertEquals(sketchLastModified, lastModifiedMillis(sketchFiles),
				"Second benchmark trial should reuse the persisted join-estimator sketches instead of rebuilding them");
	}

